My counter component renders the initial count but never updates when I click + or -. The clicks do fire (I see console logs in update). What's wrong? Here's the view:

```ts
import { component, div, button, text } from '@llui/dom'

export const Counter = component<{ count: number }, { type: 'inc' } | { type: 'dec' }>({
  init: () => ({ count: 0 }),
  update: (s, m) => (m.type === 'inc' ? { count: s.count + 1 } : { count: s.count - 1 }),
  view: ({ state, send }) => {
    const n = state.peek().count
    return [
      div({ class: 'counter' }, [
        button({ onClick: () => send({ type: 'dec' }) }, [text('-')]),
        text(String(n)),
        button({ onClick: () => send({ type: 'inc' }) }, [text('+')]),
      ]),
    ]
  },
})
```

